insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('1343f548-2ed3-5c41-bf73-609ff9450f98', 'en', 'fifa-youtube-preferred-platform-world-cup-2026', 'FIFA selects YouTube as preferred platform for World Cup 2026 coverage', 'A streaming-platform partnership could shape how fans discover tournament clips and coverage.', 'FIFA''s platform strategy is becoming part of the World Cup viewing story. A preferred YouTube relationship could make official clips, highlights and fan-facing video content easier to discover before and during the tournament.', 'FIFA selects YouTube as preferred platform for World Cup 2026 coverage', 'A streaming-platform partnership could shape how fans discover tournament clips and coverage.') on conflict (article_id, language_code) do nothing;
