insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('7afd9830-b8c5-520a-bf28-3f808c62fa2c', 'en', 'visa-hdfc-world-cup-fan-access-promotion', 'Visa and HDFC Bank launch World Cup fan access promotion', 'A new India-focused card promotion adds another route for fans planning World Cup travel.', 'Visa and HDFC Bank introduced a World Cup-linked promotion for Indian fans, showing how travel, payments and fan experiences are converging ahead of 2026. For CupMate users, these developments matter when planning cross-border trips and ticket-adjacent experiences.', 'Visa and HDFC Bank launch World Cup fan access promotion', 'A new India-focused card promotion adds another route for fans planning World Cup travel.') on conflict (article_id, language_code) do nothing;
