insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('a047d532-eb2a-5aed-a3d4-27433bac5815', 'en', 'lays-world-cup-inspired-flavors-canada', 'Lay''s introduces World Cup-inspired flavors in Canada', 'Tournament marketing is accelerating in Canada with new FIFA World Cup themed snack flavors.', 'World Cup brand activations are expanding across Canada as Lay''s introduces tournament-inspired flavors. These sponsorship and retail signals help show which host markets are ramping up fan engagement before kickoff.', 'Lay''s introduces World Cup-inspired flavors in Canada', 'Tournament marketing is accelerating in Canada with new FIFA World Cup themed snack flavors.') on conflict (article_id, language_code) do nothing;
insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('187e5bea-799c-59d2-a035-43f4b062ccf2', 'news', 'published', 'Fan Experience', 'https://media.khou.com/assets/KHOU/images/b17b757d-53e4-4fcd-8b65-69ad8d492722/20260312T161923/b17b757d-53e4-4fcd-8b65-69ad8d492722_1080x1920.jpg', 'https://www.khou.com/article/money/business/houston-business-journal/fifa-world-cup-houston-legends-loft-fan-festival/285-8c399bab-79f1-45ba-8515-6c351130cdb4', '2026-03-12T21:00:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('187e5bea-799c-59d2-a035-43f4b062ccf2', 'en', 'houston-premium-world-cup-fan-experience', 'Houston adds a premium fan experience for World Cup visitors', 'Houston''s tournament preparations include new hospitality and fan-experience offerings.', 'Houston is adding premium fan-experience inventory around the 2026 World Cup, another sign that host cities are building layered offerings for visitors beyond match tickets. CupMate can surface these updates alongside stadium routes and city recommendations.', 'Houston adds a premium fan experience for World Cup visitors', 'Houston''s tournament preparations include new hospitality and fan-experience offerings.') on conflict (article_id, language_code) do nothing;
insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('8669583d-82a2-4e3f-8275-8e919d9617e9', 'news', 'published', 'Music', null, 'https://www.fifa.com/en/articles/shakira-and-burna-boy-dai-dai-the-official-song', '2026-05-15T00:00:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('8669583d-82a2-4e3f-8275-8e919d9617e9', 'en', 'dai-dai-world-cup-song-shakira-burna-boy', 'Dai Dai becomes the official World Cup 2026 song', 'Shakira and Burna Boy''s official track adds a new music and fan-event layer to tournament planning.', 'FIFA''s official World Cup 2026 song is now out, with Shakira and Burna Boy combining Latin pop and Afrobeats on Dai Dai. The release gives the tournament a clearer cultural identity less than a month before kickoff.\n\nFor fans, this is more than a playlist update. Official songs usually travel through stadium build-up, broadcast packages, social clips, sponsor content and host-city fan festivals. That can change how early people arrive, which fan events become crowded and how much time supporters should leave around ceremonies.\n\nCupMate will track the practical side: where music programming appears, which fan events require registration and whether entertainment windows affect match-day transport or post-match movement.', 'Dai Dai becomes the official World Cup 2026 song', 'Shakira and Burna Boy''s official track adds a new music and fan-event layer to tournament planning.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('8669583d-82a2-4e3f-8275-8e919d9617e9', 'ru', 'dai-dai-ofitsialnaya-pesnya-chm-2026', 'Dai Dai стала официальной песней ЧМ-2026', 'Трек Shakira и Burna Boy добавляет турниру музыкальный слой для церемоний, фан-зон и трансляций.', 'FIFA выпустила официальную песню Чемпионата мира 2026: Shakira и Burna Boy объединили латиноамериканский поп и Afrobeats в Dai Dai. Для турнира это уже не просто музыкальная новость, а часть культурной упаковки перед стартом.\n\nДля болельщиков такие релизы важны практически. Официальная песня обычно появляется в заставках трансляций, на стадионах, в клипах, спонсорских активациях и фан-зонах. Это может влиять на то, какие площадки станут популярнее и где стоит закладывать больше времени.\n\nCupMate будет отслеживать, где музыкальная программа превращается в реальное событие: нужна ли регистрация, как это связано с транспортом и не конфликтует ли с матчевым расписанием.', 'Dai Dai стала официальной песней ЧМ-2026', 'Трек Shakira и Burna Boy добавляет турниру музыкальный слой для церемоний, фан-зон и трансляций.') on conflict (article_id, language_code) do nothing;
insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('8bb6f6b8-830a-4d44-b928-1a77bfcdea7a', 'news', 'published', 'Commerce', null, 'https://inside.fifa.com/tournament-organisation/commercial/media-releases/pif-official-tournament-supporter-world-cup-2026', '2026-05-14T13:00:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('8bb6f6b8-830a-4d44-b928-1a77bfcdea7a', 'en', 'pif-world-cup-tournament-supporter', 'PIF becomes a World Cup 2026 tournament supporter', 'FIFA''s new commercial deal brings Saudi investment, gaming and entertainment companies into the fan-engagement layer.', 'FIFA named Saudi Arabia''s Public Investment Fund as an official tournament supporter for World Cup 2026 in North America and Asia. The agreement includes PIF companies such as Savvy Games Group and Qiddiya City, connecting the tournament to sports investment, entertainment and digital engagement.\n\nFor supporters, commercial partnerships matter when they appear in useful places: fan zones, free activations, gaming tie-ins, hospitality areas or city programming. They do not change the match schedule, but they can shape what surrounds a match day.\n\nCupMate will keep these updates separate from ticket access. A sponsor experience can be useful, but fans still need official tickets, confirmed transport and clear registration details before building plans around it.', 'PIF becomes a World Cup 2026 tournament supporter', 'FIFA''s new commercial deal brings Saudi investment, gaming and entertainment companies into the fan-engagement layer.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('8bb6f6b8-830a-4d44-b928-1a77bfcdea7a', 'ru', 'pif-stal-turnirnym-partnerom-chm-2026', 'PIF стал турнирным партнером ЧМ-2026', 'Новая коммерческая сделка FIFA выводит саудовский инвестфонд, gaming и entertainment-проекты в фанатский слой турнира.', 'FIFA назвала Public Investment Fund из Саудовской Аравии официальным турнирным партнером Чемпионата мира 2026 в Северной Америке и Азии. В сделку входят компании PIF, включая Savvy Games Group и Qiddiya City.\n\nДля болельщиков коммерческие партнерства важны тогда, когда они появляются в конкретных местах: фан-зонах, бесплатных активациях, игровых проектах, hospitality-зонах или городской программе. Они не меняют расписание матчей, но могут менять то, что происходит вокруг игрового дня.\n\nCupMate будет отделять такие активности от доступа к билетам. Спонсорский опыт может быть полезен, но планировать его стоит только после проверки регистрации, локации и связи с официальными каналами турнира.', 'PIF стал турнирным партнером ЧМ-2026', 'Новая коммерческая сделка FIFA выводит саудовский инвестфонд, gaming и entertainment-проекты в фанатский слой турнира.') on conflict (article_id, language_code) do nothing;
insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('4a226a4f-549a-42f8-bdce-14d05090fda9', 'news', 'published', 'Transport', null, 'https://www.axios.com/local/boston/2026/05/13/boston-stadium-gillette-foxborough-world-cup-tickets', '2026-05-13T20:07:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('4a226a4f-549a-42f8-bdce-14d05090fda9', 'en', 'boston-stadium-ticket-access-rules', 'Boston Stadium access rules tighten for World Cup match days', 'Officials are warning fans without tickets not to come to the stadium area, while trains, buses and parking need advance planning.', 'Boston''s World Cup logistics are now practical enough for fans to plan around. Local officials are telling people without match tickets not to come to the Foxborough stadium area, where parking, tailgating and fan experiences will be limited to ticket holders.\n\nThe official Boston travel guide points to a pre-booked match-day model. Stadium trains, official express buses and parking all require planning ahead, and several options require proof of a match-day ticket before boarding or entering. Road traffic around Route 1 is expected to be heavy for hours around each match.\n\nCupMate users should save a primary transport mode, keep ticket proof accessible and choose a post-match meeting point away from the densest queues. Fans without stadium tickets should plan around Boston Fan Festival or approved watch parties instead.', 'Boston Stadium access rules tighten for World Cup match days', 'Officials are warning fans without tickets not to come to the stadium area, while trains, buses and parking need advance planning.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('4a226a4f-549a-42f8-bdce-14d05090fda9', 'ru', 'boston-stadium-dostup-v-dni-matchey', 'Boston Stadium ужесточает доступ в дни матчей', 'Болельщиков без билетов просят не ехать к стадиону, а поезд, автобус и парковку нужно планировать заранее.', 'Логистика Бостона к Чемпионату мира стала достаточно конкретной для планирования. Местные власти предупреждают: без билета на матч не стоит ехать в район стадиона в Фоксборо, где парковка, tailgating и фанатские активности будут ограничены для обладателей билетов.\n\nОфициальный travel guide описывает модель, где почти все нужно бронировать заранее. Поезда к Boston Stadium, экспресс-автобусы и парковка требуют предварительного планирования, а часть вариантов предполагает проверку билета на матч перед посадкой или въездом.\n\nCupMate-план для Бостона должен включать выбранный транспорт, доступное подтверждение билета и точку встречи после матча вне самых плотных очередей. Если билета на стадион нет, лучше планировать Fan Festival или официальные watch parties.', 'Boston Stadium ужесточает доступ в дни матчей', 'Болельщиков без билетов просят не ехать к стадиону, а поезд, автобус и парковку нужно планировать заранее.') on conflict (article_id, language_code) do nothing;
insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('2fa4a303-92cd-5087-8a31-17e4e7fc8afe', 'news', 'published', 'Safety', null, 'https://www.techradar.com/pro/security/one-month-out-from-the-world-cup-and-scammers-are-already-targeting-fans-heres-what-to-look-out-for', '2026-05-16T18:35:00+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('2fa4a303-92cd-5087-8a31-17e4e7fc8afe', 'en', 'world-cup-scam-warning-ticket-travel-apps', 'World Cup scam warnings now include tickets, hotels and transport apps', 'Kaspersky warnings reported by TechRadar show scammers targeting World Cup fans with fake tickets, accommodation offers, transport apps and business emails.', 'A new TechRadar report says Kaspersky is seeing World Cup 2026 scam activity aimed at fans heading to Mexico, the United States and Canada. The warning covers fake ticket offers, accommodation traps, bogus transport apps, dark-web travel deals and business partnership emails that use tournament urgency to extract money or credentials.\n\nThe latest warning is not limited to match tickets. Scammers are also targeting fans while they search for hotel rooms, transport to stadiums and cheaper travel packages. That mix matters because World Cup planning pushes supporters to make several expensive decisions under time pressure.\n\nCupMate users should treat safety checks as part of match-day planning. Start from official ticketing, confirm every travel vendor independently, avoid social-media sellers and save a clean paper trail before adding a booking to the itinerary.', 'World Cup scam warnings now include tickets, hotels and transport apps', 'Kaspersky warnings reported by TechRadar show scammers targeting World Cup fans with fake tickets, accommodation offers, transport apps and business emails.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('2fa4a303-92cd-5087-8a31-17e4e7fc8afe', 'ru', 'preduprezhdeniya-o-moshennichestve-chm-bilety-oteli-transport', 'Предупреждения о мошенничестве ЧМ теперь касаются билетов, отелей и транспорта', 'Предупреждения Kaspersky, о которых пишет TechRadar, показывают риски фейковых билетов, жилья, транспортных приложений и деловых писем.', 'Новый материал TechRadar сообщает, что Kaspersky фиксирует активность мошенников вокруг Чемпионата мира 2026. Риски касаются болельщиков, которые едут в Мексику, США и Канаду: фейковые билеты, предложения жилья, поддельные транспортные приложения, сомнительные travel deals и письма о несуществующих партнерствах.\n\nВажно, что угроза уже не ограничивается только билетами. Болельщики одновременно ищут отели, маршруты до стадионов и более дешевые варианты поездки, а мошенники используют срочность перед стартом турнира.\n\nCupMate должен трактовать проверку безопасности как часть планирования. Лучше начинать с официальных ticketing-каналов, отдельно подтверждать каждого travel-поставщика, избегать продавцов из соцсетей и сохранять чистую историю платежей и бронирований.', 'Предупреждения о мошенничестве ЧМ теперь касаются билетов, отелей и транспорта', 'Предупреждения Kaspersky, о которых пишет TechRadar, показывают риски фейковых билетов, жилья, транспортных приложений и деловых писем.') on conflict (article_id, language_code) do nothing;
insert into public.articles (id, type, status, category, image_url, source_url, published_at) values ('ea9523e0-d27f-5f56-92d5-ff4ac1799cd7', 'news', 'published', 'Transport', null, 'https://www.axios.com/local/kansas-city/2026/05/15/dutch-fans-march-arrowhead-kcpd-world-cup', '2026-05-15T11:22:04+00:00') on conflict (id) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('ea9523e0-d27f-5f56-92d5-ff4ac1799cd7', 'en', 'dutch-fans-kansas-city-march-warning', 'Kansas City police warn Dutch fans not to march nine miles to Arrowhead', 'KCPD says Dutch supporters should not walk from the Kansas City Fan Fest to Arrowhead Stadium for the Netherlands-Tunisia World Cup match.', 'Axios Kansas City reported that local police are warning Dutch supporters not to try a traditional Oranje fan march from downtown Kansas City to Arrowhead Stadium. The Netherlands play Tunisia there on June 25, but the Fan Fest-to-stadium route is about nine miles and would likely push fans toward I-70 instead of a normal one-hour city walk.\n\nDutch supporters are famous for orange fan walks, but Kansas City''s geography makes this one different. Axios reported that KCPD Chief Stacey Graves said the department is ready for large crowds but called a downtown-to-Arrowhead walk a bad idea for safety reasons.\n\nFans can still preserve the pre-match atmosphere without turning the route into a safety problem. The practical plan is to use Fan Fest for the gathering, follow official transport for the stadium leg and leave enough time for security, queues and post-match dispersal.', 'Kansas City police warn Dutch fans not to march nine miles to Arrowhead', 'KCPD says Dutch supporters should not walk from the Kansas City Fan Fest to Arrowhead Stadium for the Netherlands-Tunisia World Cup match.') on conflict (article_id, language_code) do nothing;
insert into public.article_translations (article_id, language_code, slug, title, excerpt, body, seo_title, seo_description) values ('ea9523e0-d27f-5f56-92d5-ff4ac1799cd7', 'ru', 'kansas-city-preduprezhdaet-niderlandskih-fanatov-o-marche', 'Kansas City предупреждает нидерландских фанатов: не идти пешком к Arrowhead', 'KCPD говорит, что болельщикам Нидерландов не стоит идти пешком от Fan Fest к Arrowhead Stadium на матч с Тунисом.', 'Axios Kansas City сообщил, что местная полиция предупреждает нидерландских болельщиков: не стоит пытаться повторить традиционный Oranje fan march от центра Kansas City до Arrowhead Stadium. Нидерланды сыграют там с Тунисом 25 июня, но путь от Fan Fest до стадиона составляет около девяти миль.\n\nФанатские марши Нидерландов обычно проходят как городская прогулка к стадиону. В Kansas City ситуация другая: маршрут намного длиннее и связан с I-70, поэтому KCPD считает такой поход небезопасным. По оценке полиции, пеший путь может занять около трех с половиной часов.\n\nCupMate-подход: собраться на Fan Fest, использовать официальный транспорт до стадиона и заложить запас на безопасность, очереди и выход после матча. Атмосферу можно сохранить без рискованного маршрута.', 'Kansas City предупреждает нидерландских фанатов: не идти пешком к Arrowhead', 'KCPD говорит, что болельщикам Нидерландов не стоит идти пешком от Fan Fest к Arrowhead Stadium на матч с Тунисом.') on conflict (article_id, language_code) do nothing;
